from langchain_openai import OpenAIEmbeddingsfrom langchain_qdrant import QdrantVectorStorefrom rag_chatbot.config import (    PDF_FILE,    QDRANT_PATH,    COLLECTION_NAME,    EMBEDDING_MODEL,)from rag_chatbot.loaders import load_pdffrom rag_chatbot.cleaners import clean_textfrom rag_chatbot.chunkers import chunk_faq_documentsdef ingest() -> None:    docs = load_pdf(str(PDF_FILE))    for doc in docs:        doc.page_content = clean_text(doc.page_content)        doc.metadata["source"] = "Tallinna Keeltekooli KKK"    chunks = chunk_faq_documents(docs)    if not chunks:        raise ValueError("Chunking ei andnud ühtegi chunki. Kontrolli PDF-i ja chunkerit.")    embeddings = OpenAIEmbeddings(model=EMBEDDING_MODEL)    #local on-disk Qdrant vectorstore    QdrantVectorStore.from_documents(        documents=chunks,        embedding=embeddings,        path=str(QDRANT_PATH),        collection_name=COLLECTION_NAME,    )    print(f"Ingest valmis. Salvestati {len(chunks)} chunki Qdranti.")if __name__ == "__main__":    ingest()